head.content:
body { font-family: system-ui, sans-serif; max-width: 800px; margin: 0 auto; padding: 2rem; line-height: 1.6; background: #fafafa; color: #333; }
h1, h2, h3 { color: #222; line-height: 1.2; }
h1 { font-size: 2.5rem; margin-bottom: 0.5rem; }
header { border-bottom: 1px solid #eee; padding-bottom: 1rem; margin-bottom: 2rem; }
nav a { margin-right: 1rem; color: #0066cc; text-decoration: none; }
nav a:hover { text-decoration: underline; }
footer { margin-top: 3rem; padding-top: 1rem; border-top: 1px solid #eee; color: #888; font-size: 0.9rem; }
